"use strict";(self.webpackChunkflarum_docs=self.webpackChunkflarum_docs||[]).push([[7535],{1290:e=>{e.exports=JSON.parse('{"pluginId":"default","version":"1.x","label":"1.x","banner":null,"badge":true,"noIndex":false,"className":"docs-version-1.x","isLast":true,"docsSidebars":{"guideSidebar":[{"type":"category","label":"Introduction","collapsible":false,"className":"menu__intro-category","items":[{"type":"link","label":"README","href":"/it/","docId":"README"},{"type":"link","label":"Codice di Condotta","href":"/it/code-of-conduct","docId":"code-of-conduct"},{"type":"link","label":"Note di rilascio","href":"/it/releases","docId":"releases"},{"type":"link","label":"Reporting Bugs","href":"/it/bugs","docId":"bugs"},{"type":"link","label":"FAQ","href":"/it/faq","docId":"faq"}],"collapsed":false},{"type":"category","label":"Contribute","collapsible":false,"className":"menu__contribute-category","items":[{"type":"link","label":"Contribuire a Flarum","href":"/it/contributing","docId":"contributing"},{"type":"link","label":"Docs and Translation","href":"/it/contributing-docs-translations","docId":"contributing-docs-translations"},{"type":"link","label":"Other Ways to Help","href":"/#help-the-flarum-project"}],"collapsed":false},{"type":"category","label":"Setting Up","collapsible":false,"className":"menu__install-category","items":[{"type":"link","label":"Composer","href":"/it/composer","docId":"composer"},{"type":"link","label":"Installazione","href":"/it/install","docId":"install"},{"type":"link","label":"Aggiornare la versione di Flarum","href":"/it/update","docId":"update"},{"type":"link","label":"Risoluzione dei problemi","href":"/it/troubleshoot","docId":"troubleshoot"}],"collapsed":false},{"type":"category","label":"Management","collapsible":false,"className":"menu__manage-category","items":[{"type":"link","label":"Pannello di amministrazione","href":"/it/admin","docId":"admin"},{"type":"link","label":"File di configurazione","href":"/it/config","docId":"config"},{"type":"link","label":"Estensioni","href":"/it/extensions","docId":"extensions"},{"type":"link","label":"Lingue","href":"/it/languages","docId":"languages"},{"type":"link","label":"Aspetto e Temi","href":"/it/themes","docId":"themes"},{"type":"link","label":"Configurazione Email","href":"/it/mail","docId":"mail"},{"type":"link","label":"Scheduler","href":"/it/scheduler","docId":"scheduler"},{"type":"link","label":"Console","href":"/it/console","docId":"console"}],"collapsed":false},{"type":"category","label":"Advanced","collapsible":false,"className":"menu__advanced-category","items":[{"type":"link","label":"Consuming the REST API","href":"/it/rest-api","docId":"rest-api"},{"type":"link","label":"Local Extenders","href":"/it/extenders","docId":"extenders"}],"collapsed":false}],"extendSidebar":[{"type":"category","label":"Main Concepts","collapsible":false,"className":"menu__intro-category","items":[{"type":"link","label":"README","href":"/it/extend/","docId":"extend/README"},{"type":"link","label":"Iniziare","href":"/it/extend/start","docId":"extend/start"},{"type":"link","label":"Sviluppo del Frontend","href":"/it/extend/frontend","docId":"extend/frontend"},{"type":"link","label":"Percorsi e contenuti","href":"/it/extend/routes","docId":"extend/routes"},{"type":"link","label":"Modelli e migrazioni","href":"/it/extend/models","docId":"extend/models"},{"type":"link","label":"API e flusso di dati","href":"/it/extend/api","docId":"extend/api"},{"type":"link","label":"Distribuzione","href":"/it/extend/distribution","docId":"extend/distribution"},{"type":"link","label":"Sviluppatori che spiegano il loro flusso di lavoro per lo sviluppo di estensioni","href":"/it/extend/cli","docId":"extend/cli"}],"collapsed":false},{"type":"category","label":"Reference Guides","collapsible":false,"className":"menu__update-category","items":[{"type":"link","label":"Pannello amministrazione","href":"/it/extend/admin","docId":"extend/admin"},{"type":"link","label":"Eventi backend","href":"/it/extend/backend-events","docId":"extend/backend-events"},{"type":"link","label":"Autorizzazione","href":"/it/extend/authorization","docId":"extend/authorization"},{"type":"link","label":"Frontend e Resolver","href":"/it/extend/frontend-pages","docId":"extend/frontend-pages"},{"type":"link","label":"Componenti interattivi","href":"/it/extend/interactive-components","docId":"extend/interactive-components"},{"type":"link","label":"Internazionalizzazione","href":"/it/extend/i18n","docId":"extend/i18n"},{"type":"link","label":"Tradurre Flarum","href":"/it/extend/language-packs","docId":"extend/language-packs"},{"type":"link","label":"Moduli e richieste","href":"/it/extend/forms","docId":"extend/forms"},{"type":"link","label":"Gruppi e autorizzazioni","href":"/it/extend/permissions","docId":"extend/permissions"},{"type":"link","label":"Impostazioni","href":"/it/extend/settings","docId":"extend/settings"},{"type":"link","label":"Static Code Analysis","href":"/it/extend/static-code-analysis","docId":"extend/static-code-analysis"},{"type":"link","label":"Test","href":"/it/extend/testing","docId":"extend/testing"},{"type":"link","label":"Guida rapida","href":"/it/extend/theme","docId":"extend/theme"},{"type":"link","label":"Views and Blade","href":"/it/extend/views","docId":"extend/views"},{"type":"link","label":"GitHub Actions (Workflows)","href":"/it/extend/github-actions","docId":"extend/github-actions"}],"collapsed":false},{"type":"category","label":"Advanced Guides","collapsible":false,"className":"menu__refs-category","items":[{"type":"link","label":"Limitazione delle API","href":"/it/extend/api-throttling","docId":"extend/api-throttling"},{"type":"link","label":"Risorse Estensione","href":"/it/extend/assets","docId":"extend/assets"},{"type":"link","label":"Console","href":"/it/extend/console","docId":"extend/console"},{"type":"link","label":"Estendere le Estensioni","href":"/it/extend/extending-extensions","docId":"extend/extending-extensions"},{"type":"link","label":"Estensibilit\xe0","href":"/it/extend/extensibility","docId":"extend/extensibility"},{"type":"link","label":"Filesystem","href":"/it/extend/filesystem","docId":"extend/filesystem"},{"type":"link","label":"Formattazione","href":"/it/extend/formatting","docId":"extend/formatting"},{"type":"link","label":"Mail","href":"/it/extend/mail","docId":"extend/mail"},{"type":"link","label":"Middleware","href":"/it/extend/middleware","docId":"extend/middleware"},{"type":"link","label":"Visibilit\xe0 Modelli","href":"/it/extend/model-visibility","docId":"extend/model-visibility"},{"type":"link","label":"Modello Slugging","href":"/it/extend/slugging","docId":"extend/slugging"},{"type":"link","label":"Notifiche","href":"/it/extend/notifications","docId":"extend/notifications"},{"type":"link","label":"Tipi di post","href":"/it/extend/post-types","docId":"extend/post-types"},{"type":"link","label":"Cerca","href":"/it/extend/search","docId":"extend/search"},{"type":"link","label":"Provider di servizi","href":"/it/extend/service-provider","docId":"extend/service-provider"}],"collapsed":false},{"type":"category","label":"Update Guides","collapsible":false,"className":"menu__advanced-category","items":[{"type":"link","label":"Updating For 1.x","href":"/it/extend/update-1_x","docId":"extend/update-1_x"},{"type":"link","label":"Updating For 1.0","href":"/it/extend/update-1_0","docId":"extend/update-1_0"},{"type":"link","label":"Aggiornamenti per Beta 16","href":"/it/extend/update-b16","docId":"extend/update-b16"},{"type":"link","label":"Aggiornamenti Beta 15","href":"/it/extend/update-b15","docId":"extend/update-b15"},{"type":"link","label":"Updating For Beta 14","href":"/it/extend/update-b14","docId":"extend/update-b14"},{"type":"link","label":"Updating For Beta 13","href":"/it/extend/update-b13","docId":"extend/update-b13"},{"type":"link","label":"Updating For Beta 12","href":"/it/extend/update-b12","docId":"extend/update-b12"},{"type":"link","label":"Updating For Beta 10","href":"/it/extend/update-b10","docId":"extend/update-b10"},{"type":"link","label":"Updating For Beta 8","href":"/it/extend/update-b8","docId":"extend/update-b8"}],"collapsed":false}],"internalSidebar":[{"type":"category","label":"Internal Docs","collapsible":false,"items":[{"type":"link","label":"Internal Team Docs","href":"/it/internal","docId":"internal/README"},{"type":"link","label":"PR Merging Policy","href":"/it/internal/merging-policy","docId":"internal/merging-policy"},{"type":"link","label":"Bundled Extensions Policy","href":"/it/internal/bundled-extensions-policy","docId":"internal/bundled-extensions-policy"},{"type":"link","label":"Extension Manager","href":"/it/internal/extension-manager","docId":"internal/extension-manager"}],"collapsed":false}]},"docs":{"admin":{"id":"admin","title":"Pannello di amministrazione","description":"Il pannello di amministrazione di Flarum un\'interfaccia user-friendly per la gestione del tuo forum. Per accedere al pannello di amministrazione, clicca sul tuo Nome nell\'angolo in alto a destra dello schermo, e scegli Amministrazione. \xc8 disponibile solo per gli utenti nel gruppo gruppo \\"Admin\\".","sidebar":"guideSidebar"},"bugs":{"id":"bugs","title":"Reporting Bugs","description":"If you discover a security vulnerability within Flarum, please follow our security policy so we can address it promptly.","sidebar":"guideSidebar"},"code-of-conduct":{"id":"code-of-conduct","title":"Codice di Condotta","description":"Benvenuti nella community di Flarum!","sidebar":"guideSidebar"},"composer":{"id":"composer","title":"Composer","description":"Flarum usa Composer per gestire le sue dipendenze ed estensioni. Dovrai usare composer per:","sidebar":"guideSidebar"},"config":{"id":"config","title":"File di configurazione","description":"C\'\xe8 solo un un eccezione in cui la configurazione di Flarum non pu\xf2 essere modificata tramite il pannello di amministrazione (escluso il database), ed \xe8 il file config.php che si trova nella radice della tua installazione di Flarum.","sidebar":"guideSidebar"},"console":{"id":"console","title":"Console","description":"Oltre al pannello di amministrazione, Flarum fornisce diversi comandi eseguibili della console per aiutarti a gestire il tuo forum tramite il terminale.","sidebar":"guideSidebar"},"contributing":{"id":"contributing","title":"Contribuire a Flarum","description":"Interessato a contribuire allo sviluppo di Flarum? \xc8 fantastico! Dalla segnalazione di un bug alla creazione di richieste particolari: ogni contributo \xe8 apprezzato e utile. Flarum non sarebbe qui senza la nostra fenomenale community.","sidebar":"guideSidebar"},"contributing-docs-translations":{"id":"contributing-docs-translations","title":"Docs and Translation","description":"Add Documentation","sidebar":"guideSidebar"},"extend/admin":{"id":"extend/admin","title":"Pannello amministrazione","description":"La Beta 15 ha introdotto un pannello di amministrazione e un frontend per le API completamente riprogettati. Ora \xe8 pi\xf9 facile che mai aggiungere impostazioni o autorizzazioni alla tua estensione.","sidebar":"extendSidebar"},"extend/api":{"id":"extend/api","title":"API e flusso di dati","description":"Nel precedente articoloabbiamo appreso come Flarum utilizza i modelli per interagire con i dati. Qui impareremo come ottenere questi dati dal database in formato JSON-API nel frontend, e farli ritornare al backend.","sidebar":"extendSidebar"},"extend/api-throttling":{"id":"extend/api-throttling","title":"Limitazione delle API","description":"Flarum viene fornito con Flarum\\\\Api\\\\Middleware\\\\ThrottleApi middleware per limitare le richieste alle API. Questo viene eseguito su ogni percorso API e le estensioni possono aggiungere la propria logica personalizzata per limitarne le richieste.","sidebar":"extendSidebar"},"extend/assets":{"id":"extend/assets","title":"Risorse Estensione","description":"Alcune estensioni potrebbero voler includere asset come immagini o file JSON nel loro codice sorgente (non si tratta di upload, che richiederebbe probabilmente un apposito filesystem).","sidebar":"extendSidebar"},"extend/authorization":{"id":"extend/authorization","title":"Autorizzazione","description":"Come con qualsiasi framework, Flarum consente di limitare determinate azioni e contenuti a determinati utenti. Esistono 2 sistemi paralleli per questo:","sidebar":"extendSidebar"},"extend/backend-events":{"id":"extend/backend-events","title":"Eventi backend","description":"Spesso, un\'estensione vorr\xe0 reagire ad alcuni eventi che si verificano da qualche parte in Flarum. Ad esempio, potremmo voler incrementare un contatore quando viene pubblicata una nuova discussione, inviare un\'e-mail di benvenuto quando un utente accede per la prima volta o aggiungere tag a una discussione prima di salvarla nel database. Questi eventi sono noti come  domain events  e vengono trasmessi attraverso il framework Laravel\'s event system.","sidebar":"extendSidebar"},"extend/cli":{"id":"extend/cli","title":"Sviluppatori che spiegano il loro flusso di lavoro per lo sviluppo di estensioni","description":"The Flarum development ecosystem is oriented around many small, modules, interacting extensions. This is a very powerful and flexible paradigm, but it also brings the maintenance cost of creating and maintaining all these extensions.","sidebar":"extendSidebar"},"extend/console":{"id":"extend/console","title":"Console","description":"Flarum consente agli sviluppatori di estensioni di aggiungere comandi personalizzati nella console oltre a quelli di default insiti nel core di Flarum.","sidebar":"extendSidebar"},"extend/distribution":{"id":"extend/distribution","title":"Distribuzione","description":"Hai scritto una grande estensione e ora vuoi che il mondo intero sia in grado di usarla. Questo documento ti guider\xe0 attraverso il processo di distribuzione, dalla configurazione di un repository Git per la tua estensione, alla pubblicazione su Packagist.","sidebar":"extendSidebar"},"extend/extending-extensions":{"id":"extend/extending-extensions","title":"Estendere le Estensioni","description":"Le estensioni di Flarum non prevedono solo l\'aggiunta di funzionalit\xe0 al core: le estensioni possono estendere anche altre estensioni!","sidebar":"extendSidebar"},"extend/extensibility":{"id":"extend/extensibility","title":"Estensibilit\xe0","description":"In alcuni casi, potresti aver bisogno di altre estensioni per estendere la tua estensione.","sidebar":"extendSidebar"},"extend/filesystem":{"id":"extend/filesystem","title":"Filesystem","description":"Flarum core si integra con il filesystem per memorizzare e servire asset (come JS/CSS compilato o caricare loghi/favicon) e avatar.","sidebar":"extendSidebar"},"extend/formatting":{"id":"extend/formatting","title":"Formattazione","description":"Flarum usa la potente libreria s9e TextFormatter per formattare i post dal semplice markup in HTML. Dovresti familiarizzare con come funziona TextFormatter prima di utilizzarlo.","sidebar":"extendSidebar"},"extend/forms":{"id":"extend/forms","title":"Moduli e richieste","description":"In questo articolo, esamineremo alcuni strumenti di frontend che sono a nostra disposizione per la creazione e la gestione di moduli, nonch\xe9 come inviare richieste HTTP tramite Flarum.","sidebar":"extendSidebar"},"extend/frontend":{"id":"extend/frontend","title":"Sviluppo del Frontend","description":"Questa pagina descrive come apportare modifiche all\'interfaccia utente di Flarum. Come aggiungere pulsanti, cornici e testo lampeggiante. \ud83e\udd29","sidebar":"extendSidebar"},"extend/frontend-pages":{"id":"extend/frontend-pages","title":"Frontend e Resolver","description":"Come spiegato nella documentazione percorsi e contenuti, possiamo usare il sistema di routing di Mithril per mostrare diversi componenti per differenti percorsi. Mithril ti consente di utilizzare qualsiasi componente che ti piace, anche un Modal o Alert, ma ti consigliamo di attenersi alle classi di componenti che ereditano il componente Page.","sidebar":"extendSidebar"},"extend/github-actions":{"id":"extend/github-actions","title":"GitHub Actions (Workflows)","description":"In public repos, GitHub Actions allow you to run jobs on every commit and pull request for free. These processes can be automated tests, builds, code inspections ..etc. You can find more information about GitHub Actions here.","sidebar":"extendSidebar"},"extend/i18n":{"id":"extend/i18n","title":"Internazionalizzazione","description":"Flarum dispone di un potente sistema di traduzione (basato sul Traduttore Symfony) che consente all\'interfaccia di visualizzare le informazioni praticamente in qualsiasi lingua. Dovresti considerare di sfruttare il traduttore di Flarum mentre sviluppi la tua estensione, anche se non hai intenzione di usarlo in pi\xf9 di una lingua.","sidebar":"extendSidebar"},"extend/interactive-components":{"id":"extend/interactive-components","title":"Componenti interattivi","description":"Spesso, hai necessit\xe0 di attivare componenti interattivi oltre a qualsiasi contenuto/animazione che hai su una determinata pagina. A seconda della natura della tua estensione, potresti voler definire elementi interattivi personalizzati o riutilizzare o estendere quelli esistenti.","sidebar":"extendSidebar"},"extend/language-packs":{"id":"extend/language-packs","title":"Tradurre Flarum","description":"Questa documentazione riguarda la struttura tecnica dei pacchetti di traduzione di Flarum. Leggi questo articolo per informazioni su come iniziare/contribuire a un pacchetto di traduzione di Flarum.","sidebar":"extendSidebar"},"extend/mail":{"id":"extend/mail","title":"Mail","description":"Oltre ai driver predefiniti nel core, Flarum consente di aggiungere nuovi driver di posta tramite estensori. Per creare il tuo driver di posta, dovrai creare una classe che implementa \\\\Flarum\\\\Mail\\\\DriverInterface. Flarum si occupa effettivamente del frontend per fornire le impostazioni di posta elettronica: basta dichiarare le impostazioni necessarie e qualsiasi valore predefinito in availableSettings.","sidebar":"extendSidebar"},"extend/middleware":{"id":"extend/middleware","title":"Middleware","description":"Il middleware \xe8 un modo ingegnoso per avvolgere la gestione delle richieste HTTP in Flarum. Ci\xf2 consente di modificare le risposte, aggiungere i propri controlli alla richiesta e molto altro ancora. Le possibilit\xe0 sono infinite!","sidebar":"extendSidebar"},"extend/model-visibility":{"id":"extend/model-visibility","title":"Visibilit\xe0 Modelli","description":"Questo articolo riguarda l\'autorizzazione, e utilizza alcuni concetti del sistema authorization. Dovresti familiarizzare con questo concetto.","sidebar":"extendSidebar"},"extend/models":{"id":"extend/models","title":"Modelli e migrazioni","description":"Nelle fondamenta, qualsiasi forum ruota intorno ai dati: gli utenti forniscono discussioni, post, informazioni sul profilo, ecc. Il nostro lavoro come sviluppatori di forum \xe8 quello di fornire una grande esperienza per la creazione, la lettura, l\'aggiornamento e l\'eliminazione di questi dati. Questo articolo vi parler\xe0 di come Flarum salvi e dia accesso a tali dati. Nel prossimo articolo spiegheremo come i dati fluiscono attraverso le API.","sidebar":"extendSidebar"},"extend/notifications":{"id":"extend/notifications","title":"Notifiche","description":"Flarum include un potente sistema di notifica per avvisare gli utenti di nuove attivit\xe0.","sidebar":"extendSidebar"},"extend/permissions":{"id":"extend/permissions","title":"Gruppi e autorizzazioni","description":"Oltre ad etichettare i ruoli, il sistema di gruppo di Flarum \xe8 un modo per applicare le autorizzazioni a segmenti di utenti.","sidebar":"extendSidebar"},"extend/post-types":{"id":"extend/post-types","title":"Tipi di post","description":"","sidebar":"extendSidebar"},"extend/README":{"id":"extend/README","title":"README","description":"- - -","sidebar":"extendSidebar"},"extend/routes":{"id":"extend/routes","title":"Percorsi e contenuti","description":"Una parte fondamentale dell\'estensione di Flarum \xe8 l\'aggiunta di percorsi, sia per esporre nuove risorse nell\'API JSON, sia per aggiungere nuove pagine al frontend.","sidebar":"extendSidebar"},"extend/search":{"id":"extend/search","title":"Cerca","description":"Flarum tratta la ricerca e il filtraggio come processi paralleli ma distinti. Quale processo viene utilizzato per gestire una richiesta a List API endpoint dipende dai parametri della query:","sidebar":"extendSidebar"},"extend/service-provider":{"id":"extend/service-provider","title":"Provider di servizi","description":"Come notato in questa documentazione, Flarum utilizza il contenitore dei servizi Laravel (o IoC container) per l\'iniezione di dipendenze. I provider di servizi consentono la configurazione e la modifica del backend Flarum a basso livello. Il caso d\'uso pi\xf9 comune per i provider di servizi \xe8 creare, modificare o sostituire i binding del contenitore. Detto questo, i provider di servizi consentono l\'accesso completo per eseguire qualsiasi logica necessaria durante l\'avvio dell\'applicazione con accesso al contenitore.","sidebar":"extendSidebar"},"extend/settings":{"id":"extend/settings","title":"Impostazioni","description":"Ad un certo punto durante la creazione di un\'estensione, potresti voler leggere alcune delle impostazioni del forum o memorizzare determinate impostazioni specifiche per la tua estensione. Per fortuna, Flarum lo rende molto semplice.","sidebar":"extendSidebar"},"extend/slugging":{"id":"extend/slugging","title":"Modello Slugging","description":"","sidebar":"extendSidebar"},"extend/start":{"id":"extend/start","title":"Iniziare","description":"Vuoi costruire un\'estensione Flarum? Sei nel posto giusto! Questo documento ti guider\ufffd attraverso alcuni concetti essenziali, dopodich\ufffd costruirai la tua prima estensione Flarum da zero.","sidebar":"extendSidebar"},"extend/static-code-analysis":{"id":"extend/static-code-analysis","title":"Static Code Analysis","description":"Static code analysis is the process of analyzing the source code against a set of rules to find bugs, code smells, and security vulnerabilities. This is a great way to improve the quality of your code and to find potential issues before they are deployed to production. An example is validating the typings of a function to ensure that the function is called with the correct arguments.","sidebar":"extendSidebar"},"extend/testing":{"id":"extend/testing","title":"Test","description":"Automated testing ensures that your extension performs as you expect it to, helps avoid introducing new bugs or regressions, and saves time on manual testing. Flarum currently provides tooling for automated backend unit and integration tests, and we plan to release support for frontend unit testing and E2E testing in the future.","sidebar":"extendSidebar"},"extend/theme":{"id":"extend/theme","title":"Guida rapida","description":"Flarum \\"themes\\" are just extensions. Typically, you\'ll want to use the Frontend extender to register custom Less and JS. Of course, you can use other extenders too: for example, you might want to support settings to allow configuring your theme.","sidebar":"extendSidebar"},"extend/update-1_0":{"id":"extend/update-1_0","title":"Updating For 1.0","description":"Flarum versione 1.0 \xe8 l\'attesissima release stabile! Questa versione porta una serie di refactor, pulizia e piccoli miglioramenti che dovrebbero rendere la vostra esperienza su Flarum migliore!","sidebar":"extendSidebar"},"extend/update-1_x":{"id":"extend/update-1_x","title":"Updating For 1.x","description":"If you need help applying these changes or using new features, please start a discussion on the community forum or Discord chat.","sidebar":"extendSidebar"},"extend/update-b10":{"id":"extend/update-b10","title":"Updating For Beta 10","description":"Beta 10 further solidifies the core architecture, offering new extenders as a stable, use-case-driven API for extending Flarum\'s core. A few small changes may necessitate updates to your extensions to make them compatible with Beta 10. These are detailed below.","sidebar":"extendSidebar"},"extend/update-b12":{"id":"extend/update-b12","title":"Updating For Beta 12","description":"Beta 12 packs several new features for extension developers, but also continues our cleanup efforts which results in a few changes, so please read this guide carefully to find out whether your extensions are affected. We invested extra effort to introduce new functionality in a backward-compatible manner or first deprecate functionality before it will be removed in the next release, in line with our versioning recommendations.","sidebar":"extendSidebar"},"extend/update-b13":{"id":"extend/update-b13","title":"Updating For Beta 13","description":"Beta 13 ships with several new extenders to simplify building and maintaining extensions. We do our best to create backward compatibility changes. We recommend changing to new Extenders as soon as they are available.","sidebar":"extendSidebar"},"extend/update-b14":{"id":"extend/update-b14","title":"Updating For Beta 14","description":"This release brings a large chunk of breaking changes - hopefully the last chunk of this size before our stable release. In order to prepare the codebase for the upcoming stable release, we decided it was time to modernize / upgrade / exchange some of the underlying JavaScript libraries that are used in the frontend. Due to the nature and size of these upgrades, we have to pass on some of the breaking changes to you, our extension developers.","sidebar":"extendSidebar"},"extend/update-b15":{"id":"extend/update-b15","title":"Aggiornamenti Beta 15","description":"La Beta 15 presenta molti nuovi extender, una riprogettazione totale del dashboard di amministrazione e molte altre interessanti funzionalit\xe0 per le estensioni. Come sempre, abbiamo fatto del nostro meglio per fornire livelli di compatibilit\xe0 con le versioni precedenti e consigliamo di abbandonare i sistemi obsoleti il prima possibile per rendere le estensioni pi\xf9 stabili.","sidebar":"extendSidebar"},"extend/update-b16":{"id":"extend/update-b16","title":"Aggiornamenti per Beta 16","description":"La Beta 16 finalizza l\'API extender PHP, introduce una libreria di test e le tipizzazioni JS, passa all\'utilizzo di namespace per le importazioni JS, aumenta la robustezza della dipendenza dalle estensioni e consente l\'override deli percorsi, tra le altre funzionalit\xe0.","sidebar":"extendSidebar"},"extend/update-b8":{"id":"extend/update-b8","title":"Updating For Beta 8","description":"All extensions will need to be refactored in order to work with beta 8. Here are the main things you will need to do in order to make your extension compatible.","sidebar":"extendSidebar"},"extend/views":{"id":"extend/views","title":"Views and Blade","description":"Although the Flarum UI you know and love is powered by our Mithril frontend, server-side generated templates are still used throughout Flarum. Most notably, the HTML skeleton of the forum, which includes various SEO meta tags, as well as the no-js view of the forum, is implemented through the Views and Blade systems.","sidebar":"extendSidebar"},"extenders":{"id":"extenders","title":"Local Extenders","description":"If there are customizations you want to make to your site without distributing an entire extension, you can do so by using local extenders. Each Flarum installation comes with an extend.php file where you can add extender instances, just like in a full extension.","sidebar":"guideSidebar"},"extensions":{"id":"extensions","title":"Estensioni","description":"Flarum \xe8 minimalista, ma \xe8 anche altamente estensibile. In effetti, la maggior parte delle funzionalit\xe0 fornite con Flarum sono in realt\xe0 estensioni!","sidebar":"guideSidebar"},"faq":{"id":"faq","title":"FAQ","description":"Flarum \xe8 stabile?","sidebar":"guideSidebar"},"install":{"id":"install","title":"Installazione","description":"Fatti un giro sul nostro forum di dimostrazione o sulla community verificata italiana Flarum.it. Oppure crea il tuo forum in pochi secondi su Free Flarum, un servizio gratuito non affiliato al team Flarum.","sidebar":"guideSidebar"},"internal/bundled-extensions-policy":{"id":"internal/bundled-extensions-policy","title":"Bundled Extensions Policy","description":"This document is to assist in deciding what core features should be bundled or maintained by the Flarum project team.","sidebar":"internalSidebar"},"internal/extension-manager":{"id":"internal/extension-manager","title":"Extension Manager","description":"This contains an explanation of how the extension manager works and what it has to offer.","sidebar":"internalSidebar"},"internal/merging-policy":{"id":"internal/merging-policy","title":"PR Merging Policy","description":"Technical contributions to the Flarum source code go through a review process. Over the years we have tuned this process based on our experiences, our targeted development speed and availability.","sidebar":"internalSidebar"},"internal/README":{"id":"internal/README","title":"Internal Team Docs","description":"This is a new documentation section, where we will be posting some docs used internally by the Flarum team. We are starting this section to provide our community with transparency as to how Flarum is run, and to help those hoping to contribute to Flarum.","sidebar":"internalSidebar"},"languages":{"id":"languages","title":"Lingue","description":"\xc8 facile aggiungere una nuova lingua all\'installazione di base di Flarum. Segui le istruzioni seguenti per scaricare e installare il language pack di tua scelta.","sidebar":"guideSidebar"},"mail":{"id":"mail","title":"Configurazione Email","description":"Qualsiasi comunit\xe0 necessita di inviare e-mail per consentire la verifica, reimpostazioni della password, notifiche e altre comunicazioni agli utenti. Configurare il tuo forum per l\'invio di email dovrebbe essere uno dei tuoi primi passi come amministratore: una configurazione errata causer\xe0 errori quando gli utenti tenteranno di registrarsi.","sidebar":"guideSidebar"},"README":{"id":"README","title":"README","description":"- - -","sidebar":"guideSidebar"},"releases":{"id":"releases","title":"Note di rilascio","description":"\x3c!--","sidebar":"guideSidebar"},"rest-api":{"id":"rest-api","title":"Consuming the REST API","description":"Flarum exposes a REST API which is used by the single page application but also available for external scripts.","sidebar":"guideSidebar"},"scheduler":{"id":"scheduler","title":"Scheduler","description":"The Flarum scheduler allows extensions to automate certain tasks effortlessly. In this guide we will see how to set it up. We won\'t go into the details of cron itself, but if you want to read more about it, I suggest you take a look at this Wikipedia article on cron.","sidebar":"guideSidebar"},"themes":{"id":"themes","title":"Aspetto e Temi","description":"Anche se abbiamo lavorato duramente per rendere Flarum il pi\xf9 bello possibile, ogni comunit\xe0 probabilmente vorr\xe0 apportare alcune modifiche grafiche o di stile per adattarlo alle proprie esigenze.","sidebar":"guideSidebar"},"troubleshoot":{"id":"troubleshoot","title":"Risoluzione dei problemi","description":"Se Flarum non si installa o non funziona come previsto, la prima cosa da fare \xe8 controllare di nuovo se il proprio ambiente soddisfa i requisiti necessari. Se ti manca qualcosa che \xe8 necessaria per l\'esecuzione di Flarum, dovrai prima rimediare.","sidebar":"guideSidebar"},"update":{"id":"update","title":"Aggiornare la versione di Flarum","description":"From the Admin Dashboard","sidebar":"guideSidebar"}}}')}}]);